(* A Stateful Random Generator *)

type seed.

op dseed: seed distr.
axiom dseed_ll: is_lossless dseed.

type state.

op dstate: ____(OP_1)____ distr.
axiom dstate_uf: is_uniform dstate.
axiom dstate_fu: is_full dstate.

type output.

op ____(OP_0)____: output distr.
axiom dout_uf: is_uniform dout.

op Fc : seed -> state -> state * output.

module SRG = {
  var s : seed
  var st: state

  proc init(): unit = {
    s <$ dseed;
    st <$ dstate;
  }

  proc next(): output = {
    var r;
    (st,r) <- Fc s st;
    return r;
  }
}.

(* A Pseudo-Random Generator *)

theory PRG.
  type output.
  op dout: output distr.

  module type PRG = {
    proc init(): unit
    proc next(): output
  }.

  module type PRGA = {
    proc next(): output
  }.

  module type Distinguisher(G: ____(MODULE_0)____) = { proc distinguish(): bool }.

  module IND(G: PRG, D: Distinguisher) = {
    module D = D(G)

    proc main(): bool = {
      var b;

      G.init();
      b <@ D.distinguish();
      return b;
    }
  }.

  module PRGi: PRG, PRGA = {
    proc init(): unit = {}
    proc next(): output = { var r; r <$ PRG.dout; return r; }
  }.

end PRG.

